init_eqs:
//LED Color Initialization
choosecol1 = int(rand(3));
choosecol2 = int(rand(3));

redcolor1 = if (choosecol1 == 0, 1, 0);
greencolor1 = if (choosecol1 == 1, 1, 0);
bluecolor1 = if (choosecol1 == 2, 1, 0);

redcolor2 = if (choosecol2 == 0, 1, 0);
greencolor2 = if (choosecol2 == 1, 1, 0);
bluecolor2 = if (choosecol2 == 2, 1, 0);

//Base Model Color Initialization
//Fun Fact: The rand() function without int() actually returns a float.
basemodelcolr = rand(1);
basemodelcolg = rand(1);
basemodelcolb = rand(1);

frame_eqs:
//LED Color Transfer
q1 = redcolor1;
q2 = greencolor1;
q3 = bluecolor1;

q4 = redcolor2;
q5 = greencolor2;
q6 = bluecolor2;

//Base Model Color Transfer
q10 = basemodelcolr;
q11 = basemodelcolg;
q12 = basemodelcolb;

//Misc. Transfer
q7 = (bass+mid+treb)/2;
q8 = aspecty/1.5;

//Disabling things
wave_a = 0;
warp = 0;
decay = 0;

shape_0_per_frame:
//Treble Part

x = instance/25+.52215;

//1st LED
r = if(instance == 1, q1, 0);
g = if(instance == 1, q2, 0);
b = if(instance == 1, q3, 0);

//2nd LED - 25%
r += if(instance == 2, q1-.25, 0);
g += if(instance == 2, q2-.25, 0);
b += if(instance == 2, q3-.25, 0);

r += if(instance == 2, q4+.25, 0);
g += if(instance == 2, q5+.25, 0);
b += if(instance == 2, q6+.25, 0);

//3rd LED - 75%
r += if(instance == 3, q1-.75, 0);
g += if(instance == 3, q2-.75, 0);
b += if(instance == 3, q3-.75, 0);

r += if(instance == 3, q4+.75, 0);
g += if(instance == 3, q5+.75, 0);
b += if(instance == 3, q6+.75, 0);

//4th LED
r += if(instance == 4, q4, 0);
g += if(instance == 4, q5, 0);
b += if(instance == 4, q6, 0);

//Music Reaction: Treble:

a = if (instance == 1, if(treb>1, 1, 0), 0);
a += if (instance == 2, if(treb>1.5, 1, 0), 0);
a += if (instance == 3, if(treb>2, 1, 0), 0);
a += if (instance == 4, if(treb>2.5, 1, 0), 0);

//The Base Model
r += if(instance == 0, q10, 0);
g += if(instance == 0, q11, 0);
b += if(instance == 0, q12, 0);
a += if(instance == 0, .35, 0);
x += if(instance == 0, -.02225, 0);
rad += if (instance == 0, q8, 0);

